```csharp
using System;
using System.Windows.Forms;

public class Form1 : Form {
    public Form1() {
        KeyDown += new KeyEventHandler(Form1_KeyDown);
    }

    private void Form1_KeyDown(object sender, KeyEventArgs e) {
        if (e.KeyCode == Keys.Escape) {
            // Escape key pressed
            Close();
        }
    }
}
